import{_ as t,o as a,c as i,a3 as s}from"./chunks/framework.CRbjHCyB.js";const k=JSON.parse('{"title":"Lint","description":"","frontmatter":{},"headers":[],"relativePath":"clice/features/lint.md","filePath":"en/clice/features/lint.md"}'),l={name:"clice/features/lint.md"};function c(n,e,r,o,d,h){return a(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="lint" tabindex="-1">Lint <a class="header-anchor" href="#lint" aria-label="Permalink to &quot;Lint&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>clice integrates clang-tidy as a built-in linting engine. Unlike standalone clang-tidy which processes each TU independently, clice&#39;s architecture enables cross-TU coordination to eliminate redundant work.</p><p><strong>Usage</strong>: <code>clice lint</code> (not yet implemented)</p><h2 id="current-status" tabindex="-1">Current Status <a class="header-anchor" href="#current-status" aria-label="Permalink to &quot;Current Status&quot;">​</a></h2><ul class="contains-task-list"><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Basic clang-tidy integration (single-TU, in-editor diagnostics)</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Project-wide lint via CLI (<code>clice lint</code>)</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Cross-TU header deduplication</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Incremental re-lint (only changed files)</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Lint result caching</li></ul><h2 id="cross-tu-optimization" tabindex="-1">Cross-TU Optimization <a class="header-anchor" href="#cross-tu-optimization" aria-label="Permalink to &quot;Cross-TU Optimization&quot;">​</a></h2><h3 id="the-problem" tabindex="-1">The Problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The Problem&quot;">​</a></h3><p>clang-tidy processes each translation unit independently. A header included by N source files gets checked N times — multiplicative overhead that makes project-wide linting slow for large codebases.</p><h3 id="clice-s-approach" tabindex="-1">clice&#39;s Approach <a class="header-anchor" href="#clice-s-approach" aria-label="Permalink to &quot;clice&#39;s Approach&quot;">​</a></h3><p>As a persistent server with knowledge of the full compilation graph, clice can:</p><ul class="contains-task-list"><li class="task-list-item"><input class="task-list-item-checkbox" checked="" disabled="" type="checkbox"> Track which headers are shared across TUs</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Hash declaration contents to skip re-checking identical declarations seen in prior TUs</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Schedule lint jobs with dependency awareness (lint shared headers once, propagate results)</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Cache per-header lint results keyed by content hash + check configuration</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Per-file diagnostic deduplication (basic: remove duplicates within a single TU)</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Project-wide diagnostic deduplication (advanced: same warning in same header across TUs → show once)</li></ul><h3 id="expected-speedup" tabindex="-1">Expected Speedup <a class="header-anchor" href="#expected-speedup" aria-label="Permalink to &quot;Expected Speedup&quot;">​</a></h3><p>For a project with H shared headers and N TUs, standalone clang-tidy does O(N × H) work. With cross-TU dedup, clice is designed for incremental checking — the goal is to check each header once regardless of how many TUs include it.</p><h2 id="clang-tidy-integration-quality" tabindex="-1">clang-tidy Integration Quality <a class="header-anchor" href="#clang-tidy-integration-quality" aria-label="Permalink to &quot;clang-tidy Integration Quality&quot;">​</a></h2><p>Issues that affect the quality of clang-tidy diagnostics within a language server:</p><ul class="contains-task-list"><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Suppress clang-tidy warnings from macros in system headers (<a href="https://github.com/clangd/clangd/issues/1587" target="_blank" rel="noreferrer">clangd#1587</a>, <a href="https://github.com/clangd/clangd/issues/2000" target="_blank" rel="noreferrer">clangd#2000</a>)</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Run checks on preprocessor directives in preamble (header guards, macros) (<a href="https://github.com/clangd/clangd/issues/2501" target="_blank" rel="noreferrer">clangd#2501</a>, <a href="https://github.com/clangd/clangd/issues/160" target="_blank" rel="noreferrer">clangd#160</a>)</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Configurable diagnostic severity per check category (<a href="https://github.com/clangd/clangd/issues/1937" target="_blank" rel="noreferrer">clangd#1937</a>)</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Support loading clang-tidy plugins (<a href="https://github.com/clangd/clangd/issues/1458" target="_blank" rel="noreferrer">clangd#1458</a>)</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Clang static analyzer support (<a href="https://github.com/clangd/clangd/issues/905" target="_blank" rel="noreferrer">clangd#905</a>)</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Clean up replacements when applying clang-tidy fixes (<a href="https://github.com/clangd/clangd/issues/429" target="_blank" rel="noreferrer">clangd#429</a>)</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Filter diagnostics by version control diff (<a href="https://github.com/clangd/clangd/issues/822" target="_blank" rel="noreferrer">clangd#822</a>)</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> NOLINT / NOLINTNEXTLINE / NOLINTBEGIN-END comment suppression</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> <code>Diagnostics.ClangTidy</code> configuration in <code>.clangd</code> config</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Fast-check filtering for clang-tidy performance</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Fix-it suggestions from clang-tidy as code actions</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Diagnostic metadata: check name, documentation URL, source tag</li></ul><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>Respects standard <code>.clang-tidy</code> configuration files in the project tree.</p><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Date</th><th>Change</th><th>PR</th></tr></thead><tbody><tr><td>—</td><td>Stub implementation, dependency graph tracking</td><td>—</td></tr></tbody></table>',21)])])}const u=t(l,[["render",c]]);export{k as __pageData,u as default};
